def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  import scala.collection.mutable

  // Sort edges by time to process them in increasing order
  val sortedEdges = edges.sortBy(edge => edge(2))

  // Union-Find (Disjoint Set Union) data structure
  val parent = (0 until n).toArray
  val rank = Array.fill(n)(1L)

  def find(u: Long): Long = {
    var u_ = u
    while (parent(u_) != u_) {
      parent(u_) = parent(parent(u_)) // Path compression
      u_ = parent(u_)
    }
    u_
  }

  def union(u: Long, v: Long): Boolean = {
    val uRoot = find(u)
    val vRoot = find(v)
    if (uRoot == vRoot) return false
    // Union by rank
    if (rank(uRoot) < rank(vRoot)) {
      parent(uRoot) = vRoot
    } else {
      parent(vRoot) = uRoot
      if (rank(uRoot) == rank(vRoot)) {
        rank(uRoot) += 1
      }
    }
    true
  }

  // Initialize the number of connected components
  var components = n

  // Iterate through edges in order of increasing time
  for (edge <- sortedEdges) {
    val u = edge(0)
    val v = edge(1)
    val time = edge(2)
    // If the edge connects two different components, merge them
    if (find(u) != find(v)) {
      union(u, v)
      components -= 1
    }
    // Check if we have at least k components
    if (components >= k) {
      return time
    }
  }

  // If we haven't found the answer, return the maximum time (all edges are removed)
  Long.MaxValue
}
